class Solution {
    public int[] memLeak(int memory1, int memory2) {
        int crashTime = 1;
        int memory1Crash = memory1;
        int memory2Crash = memory2;
        while (true) {
            if (memory1 >= memory2) {
                memory1 -= crashTime;
                if (memory1 < 0) {
                    memory1Crash = -memory1;
                    break;
                }
            } else {
                memory2 -= crashTime;
                if (memory2 < 0) {
                    memory2Crash = -memory2;
                    break;
                }
            }
            crashTime++;
        }
        return new int[] {crashTime, memory1Crash, memory2Crash};
    }
}
```

